mapper.select:
/* 장치그룹정보 조회 */ SELECT dv_grp.site_id , dv_grp.device_grp_idx , dv_grp.device_grp_name , dv.device_id , dv.device_name , dv.device_type , al.alarm_type , al.alarm_act_yn , al.alarm_cfm_yn , SUM(case when al.alarm_type=1 then 1 ELSE 0 END) over (PARTITION BY device_grp_idx) AS a1_cnt , SUM(case when al.alarm_type=2 then 1 ELSE 0 END) over (PARTITION BY device_grp_idx) AS a2_cnt FROM ( SELECT dg.device_grp_idx , dg.device_grp_name , dg.site_id FROM tb_device_group dg WHERE 1=1
AND dg.site_id = #{siteId}
AND dg.del_yn = 'N' )dv_grp INNER JOIN tb_device dv ON dv_grp.device_grp_idx = dv.device_grp_idx AND dv_grp.site_id = dv.site_id AND dv.del_yn = 'N' LEFT OUTER JOIN ( SELECT * FROM tb_alarm WHERE alarm_act_yn = 'N'
AND site_id = #{siteId}
GROUP BY site_id, device_id, device_type, alarm_type )al ON dv.device_id = al.device_id AND dv.device_type = al.device_type ORDER BY dv.device_grp_idx, dv.device_id

/* 장치 중복여부 체크 */
select 
	count(*) as cnt 
from tb_device
where site_id = #{siteId }
and device_id = #{deviceId }
and device_type = #{deviceType }
